mapper.insert:
insert into note (
content,
created_at,
updated_at
)
values (
#{content},
#{createdAt},
#{updatedAt}
)

mapper.update:
update note
set content = #{content},
updated_at = #{updatedAt}
where id = #{id}

mapper.select:
select id, content, created_at, updated_at from note
content like concat('%', #{content}, '%')
order by id desc limit #{offset}, #{pageSize}
